import subprocess
import os
import json
import tempfile
import pytest

SOLUTION_DIR = os.path.join(os.path.dirname(__file__), "solution")
SOLUTION_FILE = os.path.join(SOLUTION_DIR, "Solution.swift")

HARNESS_CODE = r'''
import Foundation

struct TestResult: Codable {
    var name: String
    var value: String
}

@main
struct Harness {
    static func main() {
        let encoder = JSONEncoder()
        encoder.outputFormatting = .prettyPrinted

        func arrayToString(_ arr: [String]) -> String {
            let data = try! encoder.encode(arr)
            return String(data: data, encoding: .utf8)!
        }

        var results: [TestResult] = []

        // Test workspace commands
        let ws1 = buildWorkspaceCommand(workspaceName: "1", isPiped: false, consumeStdin: false)
        results.append(TestResult(name: "ws_nopipe", value: arrayToString(ws1)))

        let ws2 = buildWorkspaceCommand(workspaceName: "2", isPiped: true, consumeStdin: true)
        results.append(TestResult(name: "ws_pipe_stdin", value: arrayToString(ws2)))

        let ws3 = buildWorkspaceCommand(workspaceName: "web", isPiped: true, consumeStdin: false)
        results.append(TestResult(name: "ws_pipe_nostdin", value: arrayToString(ws3)))

        let ws4 = buildWorkspaceCommand(workspaceName: "mail", isPiped: false, consumeStdin: true)
        results.append(TestResult(name: "ws_nopipe_consume", value: arrayToString(ws4)))

        // Test move-node commands
        let mn1 = buildMoveNodeCommand(workspaceName: "3", isPiped: false, consumeStdin: false)
        results.append(TestResult(name: "mn_nopipe", value: arrayToString(mn1)))

        let mn2 = buildMoveNodeCommand(workspaceName: "4", isPiped: true, consumeStdin: true)
        results.append(TestResult(name: "mn_pipe_stdin", value: arrayToString(mn2)))

        let mn3 = buildMoveNodeCommand(workspaceName: "dev", isPiped: true, consumeStdin: false)
        results.append(TestResult(name: "mn_pipe_nostdin", value: arrayToString(mn3)))

        let mn4 = buildMoveNodeCommand(workspaceName: "music", isPiped: false, consumeStdin: true)
        results.append(TestResult(name: "mn_nopipe_consume", value: arrayToString(mn4)))

        // Test persistent workspaces config
        let pw1 = generatePersistentWorkspacesConfig(workspaceNames: ["1", "2", "3"])
        results.append(TestResult(name: "pw_basic", value: pw1))

        let pw2 = generatePersistentWorkspacesConfig(workspaceNames: ["web"])
        results.append(TestResult(name: "pw_single", value: pw2))

        let pw3 = generatePersistentWorkspacesConfig(workspaceNames: [])
        results.append(TestResult(name: "pw_empty", value: pw3))

        // Test on-window-detected config
        let owd1 = generateOnWindowDetectedConfig(appId: "com.apple.Safari", commands: ["layout floating", "move-node-to-workspace 2"])
        results.append(TestResult(name: "owd_safari", value: owd1))

        let owd2 = generateOnWindowDetectedConfig(appId: "com.google.Chrome", commands: ["layout floating", "resize width 250", "move-node-to-workspace web", "layout tiling"])
        results.append(TestResult(name: "owd_chrome_multi", value: owd2))

        let owd3 = generateOnWindowDetectedConfig(appId: "com.apple.Terminal", commands: ["move-node-to-workspace 3"])
        results.append(TestResult(name: "owd_terminal", value: owd3))

        // Test on-mode-changed config
        let omc1 = generateOnModeChangedConfig(commands: ["exec-and-forget echo mode_changed"])
        results.append(TestResult(name: "omc_basic", value: omc1))

        let omc2 = generateOnModeChangedConfig(commands: ["exec-and-forget echo a", "exec-and-forget echo b"])
        results.append(TestResult(name: "omc_multi", value: omc2))

        // Test full config
        let fc1 = generateFullConfig(
            persistentWorkspaces: ["1", "2"],
            windowRules: [
                (appId: "com.apple.Safari", commands: ["layout floating", "move-node-to-workspace web"]),
                (appId: "com.apple.Terminal", commands: ["move-node-to-workspace 3"])
            ],
            modeChangedCommands: ["exec-and-forget echo changed"]
        )
        results.append(TestResult(name: "fc_full", value: fc1))

        let fc2 = generateFullConfig(
            persistentWorkspaces: [],
            windowRules: [],
            modeChangedCommands: []
        )
        results.append(TestResult(name: "fc_empty", value: fc2))

        let fc3 = generateFullConfig(
            persistentWorkspaces: ["web", "dev", "music"],
            windowRules: [],
            modeChangedCommands: ["exec-and-forget notify"]
        )
        results.append(TestResult(name: "fc_no_rules", value: fc3))

        let fc4 = generateFullConfig(
            persistentWorkspaces: [],
            windowRules: [(appId: "com.example.App", commands: ["layout floating", "resize width 100", "resize height 200"])],
            modeChangedCommands: []
        )
        results.append(TestResult(name: "fc_only_rules", value: fc4))

        // Workspace with special names
        let ws5 = buildWorkspaceCommand(workspaceName: "my-workspace", isPiped: true, consumeStdin: true)
        results.append(TestResult(name: "ws_special_name", value: arrayToString(ws5)))

        let mn5 = buildMoveNodeCommand(workspaceName: "my-workspace", isPiped: true, consumeStdin: true)
        results.append(TestResult(name: "mn_special_name", value: arrayToString(mn5)))

        // Single command on-window-detected
        let owd4 = generateOnWindowDetectedConfig(appId: "com.example.App", commands: ["layout tiling"])
        results.append(TestResult(name: "owd_single_cmd", value: owd4))

        // Empty commands for on-mode-changed
        let omc3 = generateOnModeChangedConfig(commands: [])
        results.append(TestResult(name: "omc_empty", value: omc3))

        let data = try! encoder.encode(results)
        print(String(data: data, encoding: .utf8)!)
    }
}
'''


@pytest.fixture(scope="session")
def compiled_results():
    """Compile the solution + harness and run, returning parsed results as a dict."""
    with tempfile.TemporaryDirectory() as tmpdir:
        harness_path = os.path.join(tmpdir, "Harness.swift")
        with open(harness_path, "w") as f:
            f.write(HARNESS_CODE)

        binary_path = os.path.join(tmpdir, "test_harness")

        compile_result = subprocess.run(
            ["swiftc", "-o", binary_path, SOLUTION_FILE, harness_path],
            capture_output=True, text=True, timeout=60
        )
        assert compile_result.returncode == 0, (
            f"Compilation failed:\nstdout: {compile_result.stdout}\nstderr: {compile_result.stderr}"
        )

        run_result = subprocess.run(
            [binary_path],
            capture_output=True, text=True, timeout=30
        )
        assert run_result.returncode == 0, (
            f"Execution failed:\nstdout: {run_result.stdout}\nstderr: {run_result.stderr}"
        )

        results_list = json.loads(run_result.stdout)
        return {r["name"]: r["value"] for r in results_list}


class TestBuildWorkspaceCommand:
    """Tests for buildWorkspaceCommand — must use --stdin/--no-stdin when piped."""

    def test_no_pipe(self, compiled_results):
        result = json.loads(compiled_results["ws_nopipe"])
        assert result == ["aerospace", "workspace", "1"]

    def test_pipe_with_stdin(self, compiled_results):
        result = json.loads(compiled_results["ws_pipe_stdin"])
        assert result == ["aerospace", "workspace", "--stdin", "2"]

    def test_pipe_without_stdin(self, compiled_results):
        result = json.loads(compiled_results["ws_pipe_nostdin"])
        assert result == ["aerospace", "workspace", "--no-stdin", "web"]

    def test_no_pipe_consume_ignored(self, compiled_results):
        """When not piped, consumeStdin is irrelevant — no flag should appear."""
        result = json.loads(compiled_results["ws_nopipe_consume"])
        assert result == ["aerospace", "workspace", "mail"]
        assert "--stdin" not in result
        assert "--no-stdin" not in result

    def test_special_workspace_name(self, compiled_results):
        result = json.loads(compiled_results["ws_special_name"])
        assert result == ["aerospace", "workspace", "--stdin", "my-workspace"]


