@pytest.fixture(scope="session")
def driver_binary():
    """Compile the solution with stub headers and a test driver."""
    for rel_path, content in STUB_HEADERS.items():
        full_path = os.path.join(BUILD_DIR, "stubs", rel_path)
        os.makedirs(os.path.dirname(full_path), exist_ok=True)
        with open(full_path, "w") as f:
            f.write(content)

    driver_path = os.path.join(BUILD_DIR, "driver.cpp")
    with open(driver_path, "w") as f:
        f.write(DRIVER_CPP)

    binary_path = os.path.join(BUILD_DIR, "driver")

    sol_dest = os.path.join(BUILD_DIR, "solution.cpp")
    shutil.copy2(SOLUTION_CPP, sol_dest)

    compile_cmd = [
        "g++", "-std=c++17", "-o", binary_path,
        f"-I{os.path.join(BUILD_DIR, 'stubs')}",
        f"-I{BUILD_DIR}",
        driver_path,
    ]
    result = subprocess.run(compile_cmd, capture_output=True, text=True)
    if result.returncode != 0:
        pytest.fail(f"Compilation failed:\nSTDOUT: {result.stdout}\nSTDERR: {result.stderr}")

    yield binary_path

    shutil.rmtree(BUILD_DIR, ignore_errors=True)


def run_driver(binary, *args):
    """Run the driver binary with given arguments and return stdout."""
    result = subprocess.run(
        [binary] + list(args),
        capture_output=True, text=True, timeout=10
    )
    if result.returncode != 0:
        pytest.fail(f"Driver failed with rc={result.returncode}\nSTDERR: {result.stderr}\nSTDOUT: {result.stdout}")
    return result.stdout


def extract_output(stdout):
    """Extract content between OUTPUT_START and OUTPUT_END markers."""
    start = stdout.index("OUTPUT_START\n") + len("OUTPUT_START\n")
    end = stdout.index("OUTPUT_END")
    return stdout[start:end]


def extract_ini(stdout):
    """Extract INI content."""
    start = stdout.index("INI_START\n") + len("INI_START\n")
    end = stdout.index("INI_END")
    return stdout[start:end]


def extract_cli(stdout):
    """Extract CLI content."""
    start = stdout.index("CLI_START\n") + len("CLI_START\n")
    end = stdout.index("CLI_END")
    return stdout[start:end]


class TestConvertLegacyCli:
    """Tests for convert_legacy_cli_to_settings."""

    def test_server_with_address_and_debug(self, driver_binary):
        cli = "deskflow-core server --address localhost:24800 --debug DEBUG --name myserver --no-daemon --no-tray"
        stdout = run_driver(driver_binary, "convert_legacy_cli", cli)
        ini = extract_ini(stdout)
        cmd = extract_cli(stdout)

        assert "[core]" in ini
        assert "screenName=myserver" in ini
        assert "interface=localhost" in ini
        assert "port=24800" in ini
        assert "level=5" in ini  # DEBUG -> 5
        assert "deskflow-core server --settings" in cmd

