import subprocess
import json
import os
import tempfile
import pytest

SOLUTION_DIR = os.path.join(os.path.dirname(__file__), "solution")


def run_ts_snippet(snippet: str, timeout: int = 60) -> dict:
    """Write a small TS script that imports from the solution, compile & run it, return JSON output."""
    with tempfile.NamedTemporaryFile(
        mode="w", suffix=".ts", dir=SOLUTION_DIR, delete=False
    ) as f:
        f.write(snippet)
        tmp_path = f.name

    try:
        result = subprocess.run(
            ["npx", "tsx", tmp_path],
            capture_output=True,
            text=True,
            timeout=timeout,
            cwd=SOLUTION_DIR,
        )
        if result.returncode != 0:
            result2 = subprocess.run(
                ["npx", "ts-node", "--esm", tmp_path],
                capture_output=True,
                text=True,
                timeout=timeout,
                cwd=SOLUTION_DIR,
            )
            if result2.returncode != 0:
                return {"error": True, "stderr": result.stderr + "\n" + result2.stderr, "stdout": ""}
            result = result2

        stdout = result.stdout.strip()
        if not stdout:
            return {"error": False, "raw": "", "data": None}
        try:
            return {"error": False, "raw": stdout, "data": json.loads(stdout)}
        except json.JSONDecodeError:
            return {"error": False, "raw": stdout, "data": None}
    finally:
        os.unlink(tmp_path)


def run_ts_snippet_check_no_error(snippet: str, timeout: int = 60) -> dict:
    """Run snippet and assert it doesn't error."""
    result = run_ts_snippet(snippet, timeout)
    assert not result.get("error"), f"TS execution failed: {result.get('stderr', '')}"
    return result


