import pytest
import subprocess
import json
import os


def get_solution_dir():
    solution_dir = os.path.join(os.path.dirname(__file__), "solution")
    if not os.path.isdir(solution_dir):
        solution_dir = os.path.join(os.getcwd(), "solution")
    return solution_dir


def run_ts(code: str) -> dict:
    """Compile and run a TS snippet that imports from solution.ts and prints JSON."""
    solution_dir = get_solution_dir()
    test_file = os.path.join(solution_dir, "_test_runner.ts")
    try:
        with open(test_file, "w") as f:
            f.write(code)

        result = subprocess.run(
            ["npx", "tsx", test_file],
            capture_output=True,
            text=True,
            timeout=30,
            cwd=solution_dir
        )
        if result.returncode != 0:
            raise RuntimeError(f"TS execution failed:\nSTDOUT: {result.stdout}\nSTDERR: {result.stderr}")
        return json.loads(result.stdout.strip())
    finally:
        if os.path.exists(test_file):
            os.remove(test_file)


