# Compile the Kotlin solution once before tests run
@pytest.fixture(scope="session", autouse=True)
def compile_solution():
    solution_dir = os.path.join(os.path.dirname(__file__), "solution")
    kt_file = os.path.join(solution_dir, "Solution.kt")

    # Create a main function wrapper that we can call with arguments
    wrapper_file = os.path.join(solution_dir, "Main.kt")
    wrapper_code = '''
fun main(args: Array<String>) {
    val func = args[0]
    when (func) {
        "buildModuleProp" -> {
            val id = args[1]
            val name = args[2]
            val version = args[3]
            val versionCode = args[4].toInt()
            val author = args[5]
            val description = args[6]
            val isMetamodule = args[7].toBoolean()
            print(buildModuleProp(id, name, version, versionCode, author, description, isMetamodule))
        }
        "validateModuleId" -> {
            val id = args[1]
            print(validateModuleId(id))
        }
        "generateMountCommand" -> {
            val lowerDir = args[1]
            val upperDir = args[2]
            val workDir = args[3]
            val targetDir = args[4]
            print(generateMountCommand(lowerDir, upperDir, workDir, targetDir))
        }
        "checkModuleMountReadiness" -> {
            val hasMetamodule = args[1].toBoolean()
            val moduleCount = args[2].toInt()
            print(checkModuleMountReadiness(hasMetamodule, moduleCount))
        }
        "buildBootPatchCommand" -> {
            val inputPath = args[1]
            val outputName = if (args.size > 2 && args[2] != "NULL") args[2] else null
            print(buildBootPatchCommand(inputPath, outputName))
        }
        "resolveMetamoduleConflict" -> {
            val ids = if (args.size > 1) args.drop(1) else emptyList()
            print(resolveMetamoduleConflict(ids))
        }
        "listMetamoduleHooks" -> {
            val hooks = listMetamoduleHooks()
            print(hooks.sorted().joinToString(","))
        }
    }
}
'''
    with open(wrapper_file, "w") as f:
        f.write(wrapper_code)

    # Compile
    result = subprocess.run(
        ["kotlinc", "-include-runtime", "-d", os.path.join(solution_dir, "solution.jar"),
