def run_solution(*args):
    solution_dir = os.path.join(os.path.dirname(__file__), "solution")
    jar_path = os.path.join(solution_dir, "solution.jar")
    result = subprocess.run(
        ["java", "-jar", jar_path] + list(args),
        capture_output=True, text=True, timeout=30
    )
    if result.returncode != 0:
        raise RuntimeError(f"Execution failed:\n{result.stderr}")
    return result.stdout


