def run_java_test(compiled_solution, test_name, *extra_args):
    """Run a specific test through the Java harness."""
    cmd = ["java", "-cp", compiled_solution["classpath"], "solution.TestHarness", test_name] + list(extra_args)
    result = subprocess.run(cmd, capture_output=True, text=True, timeout=30)
    if result.returncode != 0:
        raise RuntimeError(f"Java execution failed: {result.stderr}\nstdout: {result.stdout}")
    return result.stdout.strip()


def parse_output(output, prefix):
    for line in output.splitlines():
        if line.startswith(prefix):
            return line[len(prefix):]
    raise ValueError(f"Prefix '{prefix}' not found in output:\n{output}")


