import subprocess
import os
import pytest
import tempfile
import shutil

SOLUTION_DIR = os.path.join(os.path.dirname(__file__), "solution")
BUILD_DIR = tempfile.mkdtemp(prefix="quarkdown_test_")

HARNESS_CODE = r"""
fun main() {
    val args = System.getenv("TEST_FUNC")?.split("|") ?: return

    when (args[0]) {
        "buildPipeCompileCommand" -> {
            val pb = buildPipeCompileCommand(args[1])
            println("CMD:" + pb.command().joinToString("\u0000"))
        }
        "buildCompileCommand" -> {
            val pb = buildCompileCommand(args[1])
            println("CMD:" + pb.command().joinToString("\u0000"))
        }
        "parseCompileOutput" -> {
            val result = parseCompileOutput(args[1])
            println("RESULT:" + (result ?: "NULL"))
        }
        "buildBrowserCommand" -> {
            val pb = buildBrowserCommand(args[1], args[2])
            println("CMD:" + pb.command().joinToString("\u0000"))
        }
        "generateTocMarkup" -> {
            val result = generateTocMarkup(args[1].toBoolean())
            println("MARKUP:" + result)
        }
        "generateDocumentWithToc" -> {
            // args[1] = headings as "text,unnumbered;text,unnumbered;..."
            // args[2] = includeUnnumberedInToc
            val headings = if (args[1].isEmpty()) emptyList() else args[1].split(";").map {
                val parts = it.split(",")
                Pair(parts[0], parts[1].toBoolean())
            }
            val result = generateDocumentWithToc(headings, args[2].toBoolean())
            println("DOC_START")
            print(result)
            println("DOC_END")
        }
    }
}
"""


@pytest.fixture(scope="session", autouse=True)
def compile_solution():
    """Compile the Kotlin solution and test harness."""
    solution_kt = os.path.join(SOLUTION_DIR, "Solution.kt")
    assert os.path.exists(solution_kt), f"Solution.kt not found at {solution_kt}"

    with open(solution_kt, "r") as f:
        sol_content_raw = f.read()

    sol_file = os.path.join(BUILD_DIR, "Solution.kt")
    with open(sol_file, "w") as f:
        f.write(sol_content_raw)

    harness_file = os.path.join(BUILD_DIR, "TestHarness.kt")
    with open(harness_file, "w") as f:
        f.write(HARNESS_CODE)

    result = subprocess.run(
        ["kotlinc", sol_file, harness_file, "-include-runtime", "-d", os.path.join(BUILD_DIR, "test.jar")],
        capture_output=True, text=True, timeout=120
    )
    assert result.returncode == 0, f"Compilation failed:\n{result.stderr}"

    yield
    shutil.rmtree(BUILD_DIR, ignore_errors=True)


def run_func(func_name, *args):
    """Run a function from the compiled solution via the test harness."""
    env = os.environ.copy()
    env["TEST_FUNC"] = "|".join([func_name] + list(args))
    result = subprocess.run(
        ["java", "-jar", os.path.join(BUILD_DIR, "test.jar")],
        capture_output=True, text=True, timeout=30, env=env
    )
    assert result.returncode == 0, f"Runtime error: {result.stderr}"
    return result.stdout


def parse_cmd(output):
    for line in output.strip().split("\n"):
        if line.startswith("CMD:"):
            return line[4:].split("\0")
    raise ValueError(f"No CMD: line found in output: {output}")


def parse_result(output):
    for line in output.strip().split("\n"):
        if line.startswith("RESULT:"):
            val = line[7:]
            return None if val == "NULL" else val
    raise ValueError(f"No RESULT: line found in output: {output}")


def parse_markup(output):
    for line in output.strip().split("\n"):
        if line.startswith("MARKUP:"):
            return line[7:]
    raise ValueError(f"No MARKUP: line found in output: {output}")


def parse_doc(output):
    lines = output.split("\n")
    capturing = False
    doc_lines = []
    for line in lines:
        if line.strip() == "DOC_START":
            capturing = True
            continue
        if line.strip() == "DOC_END":
            break
        if capturing:
            doc_lines.append(line)
    return "\n".join(doc_lines)


