import os

SOLUTION_PATH = os.path.join(os.path.dirname(__file__), "solution", "solution.rb")


def run_ruby(code):
    """Run Ruby code that requires the solution and returns a result."""
    full_code = f'require_relative "{SOLUTION_PATH}"\n{code}'
    result = subprocess.run(
        ["ruby", "-e", full_code],
        capture_output=True,
        text=True,
        timeout=10
    )
    if result.returncode != 0:
        raise RuntimeError(f"Ruby error: {result.stderr.strip()}")
    return result.stdout.strip()


