import subprocess
import os
import tempfile
import pytest

# Compile the solution once for the entire test session
SOLUTION_DIR = os.path.join(os.path.dirname(__file__), "solution")
SOLUTION_SRC = os.path.join(SOLUTION_DIR, "solution.cpp")
SOLUTION_BIN = os.path.join(SOLUTION_DIR, "solution_bin")


@pytest.fixture(scope="session", autouse=True)
def compile_solution():
    """Compile the C++ solution once before all tests."""
    result = subprocess.run(
        ["g++", "-std=c++17", "-o", SOLUTION_BIN, SOLUTION_SRC],
        capture_output=True,
        text=True,
    )
    assert result.returncode == 0, f"Compilation failed:\n{result.stderr}"
    yield
    # Cleanup
    if os.path.exists(SOLUTION_BIN):
        os.remove(SOLUTION_BIN)


def run_solution_with_test(test_code: str) -> subprocess.CompletedProcess:
    """
    Create a temporary C++ file that includes the solution functions and runs a test,
    compile it, run it, and return the result.
    """
    with tempfile.NamedTemporaryFile(suffix=".cpp", mode="w", delete=False) as f:
        f.write(test_code)
        test_src = f.name

    test_bin = test_src.replace(".cpp", "_bin")
    try:
        comp = subprocess.run(
            ["g++", "-std=c++17", "-o", test_bin, test_src],
            capture_output=True,
            text=True,
        )
        if comp.returncode != 0:
            return subprocess.CompletedProcess(
                args=[], returncode=-1, stdout="", stderr=f"COMPILE ERROR: {comp.stderr}"
            )

        result = subprocess.run(
            [test_bin], capture_output=True, text=True, timeout=10
        )
        return result
    finally:
        if os.path.exists(test_src):
            os.remove(test_src)
        if os.path.exists(test_bin):
            os.remove(test_bin)


