skip_no_swift = pytest.mark.skipif(
    not SWIFT_AVAILABLE,
    reason="swiftc not found on PATH – cannot compile/run Swift solution",
)


def get_solution_source():
    """Read the solution source code."""
    with open(SOLUTION_FILE, "r") as f:
        return f.read()


def compile_and_run(extra_flags=None):
    """
    Compile the Swift solution and run it, returning stdout.
    The file is .cpp but contains Swift code.
    """
    binary_path = os.path.join(SOLUTION_DIR, "solution_bin")
    compile_cmd = [
        SWIFTC or "swiftc",
        "-swift-version", "6",
        "-strict-memory-safety",
        "-parse-as-library",
        SOLUTION_FILE,
        "-o", binary_path,
    ]
    if extra_flags:
        compile_cmd.extend(extra_flags)

    compile_result = subprocess.run(
        compile_cmd,
        capture_output=True,
        text=True,
        timeout=120,
    )
    if compile_result.returncode != 0:
        raise RuntimeError(
            f"Compilation failed:\nstdout: {compile_result.stdout}\nstderr: {compile_result.stderr}"
        )

    run_result = subprocess.run(
        [binary_path],
        capture_output=True,
        text=True,
        timeout=30,
    )
    if run_result.returncode != 0:
        raise RuntimeError(
            f"Execution failed (rc={run_result.returncode}):\nstdout: {run_result.stdout}\nstderr: {run_result.stderr}"
        )
    return run_result.stdout


def parse_output(stdout):
    """Parse the labeled output lines into a dict."""
    result = {}
    for line in stdout.strip().splitlines():
        line = line.strip()
        if ": " in line:
            key, value = line.split(": ", 1)
            result[key.strip()] = value.strip()
    return result


