import pytest

SOLUTION_DIR = os.path.join(os.path.dirname(__file__), "solution")
SOLUTION_FILE = os.path.join(SOLUTION_DIR, "Solution.swift")


def run_swift_test(test_code: str) -> str:
    """Compile and run a Swift test program that imports the solution."""
    with tempfile.TemporaryDirectory() as tmpdir:
        # Copy solution file
        main_path = os.path.join(tmpdir, "main.swift")
        solution_content = open(SOLUTION_FILE).read()

        # Write combined file: solution + test code
        with open(main_path, "w") as f:
            f.write(solution_content + "\n" + test_code)

        output_path = os.path.join(tmpdir, "test_binary")

        # Compile
        compile_result = subprocess.run(
            ["swiftc", "-o", output_path, main_path],
            capture_output=True, text=True, timeout=60
        )
        if compile_result.returncode != 0:
            pytest.fail(f"Compilation failed:\n{compile_result.stderr}")

        # Run
        run_result = subprocess.run(
            [output_path],
            capture_output=True, text=True, timeout=30
        )
        if run_result.returncode != 0:
            pytest.fail(f"Runtime error:\n{run_result.stderr}")

        return run_result.stdout.strip()


