import pytest
import subprocess
import json
import os
import tempfile

SOLUTION_DIR = os.path.join(os.path.dirname(__file__), "solution")
SOLUTION_PATH = os.path.join(SOLUTION_DIR, "solution.ts")


def run_ts_snippet(snippet: str) -> str:
    """Write a temporary TS file that imports from solution and run it, returning stdout."""
    with tempfile.NamedTemporaryFile(
        mode="w", suffix=".ts", dir=SOLUTION_DIR, delete=False
    ) as f:
        f.write(snippet)
        f.flush()
        tmp_path = f.name

    try:
        for runner in [["npx", "tsx"], ["npx", "ts-node", "--esm"]]:
            try:
                result = subprocess.run(
                    runner + [tmp_path],
                    capture_output=True,
                    text=True,
                    timeout=30,
                    cwd=SOLUTION_DIR,
                )
                if result.returncode == 0:
                    return result.stdout.strip()
            except (FileNotFoundError, subprocess.TimeoutExpired):
                continue

        js_path = tmp_path.replace(".ts", ".js")
        subprocess.run(
            ["npx", "tsc", "--esModuleInterop", "--module", "commonjs",
             "--target", "ES2020", "--outDir", SOLUTION_DIR, tmp_path],
            capture_output=True, text=True, timeout=30, cwd=SOLUTION_DIR
        )
        if os.path.exists(js_path):
            result = subprocess.run(
                ["node", js_path],
                capture_output=True, text=True, timeout=30, cwd=SOLUTION_DIR
            )
            if os.path.exists(js_path):
                os.unlink(js_path)
            if result.returncode == 0:
                return result.stdout.strip()
            raise RuntimeError(f"Node execution failed: {result.stderr}")

        raise RuntimeError("Could not execute TypeScript snippet")
    finally:
        if os.path.exists(tmp_path):
            os.unlink(tmp_path)


