import subprocess
import os
import json
import re
import shutil
import pytest

SOLUTION_DIR = os.path.join(os.path.dirname(os.path.abspath(__file__)), "solution")


def find_mvn():
    """Find the mvn executable."""
    # Try 'mvn' on PATH first
    mvn = shutil.which("mvn")
    if mvn:
        return mvn
    # Try common locations
    for path in ["/usr/bin/mvn", "/usr/local/bin/mvn", "/opt/maven/bin/mvn",
                 "/usr/share/maven/bin/mvn"]:
        if os.path.isfile(path) and os.access(path, os.X_OK):
            return path
    # Try mvnw in solution dir
    mvnw = os.path.join(SOLUTION_DIR, "mvnw")
    if os.path.isfile(mvnw) and os.access(mvnw, os.X_OK):
        return mvnw
    return None


def run_solution():
    """Compile and run the Java solution, returning stdout."""
    mvn = find_mvn()
    if mvn is None:
        return None, "mvn not found", -1
    result = subprocess.run(
        [mvn, "-q", "compile", "exec:java", "-Dexec.mainClass=Solution"],
        cwd=SOLUTION_DIR,
        capture_output=True,
        text=True,
        timeout=120,
    )
    return result.stdout, result.stderr, result.returncode


@pytest.fixture(scope="session")
def solution_output():
    """Run the solution once and cache the output."""
    stdout, stderr, returncode = run_solution()
    return {"stdout": stdout, "stderr": stderr, "returncode": returncode}


@pytest.fixture(scope="session")
def mvn_available():
    """Check if mvn is available."""
    return find_mvn() is not None


def parse_section(stdout, section_name):
    """Extract lines belonging to a section from the output."""
    if stdout is None:
        return ""
    lines = stdout.split("\n")
    in_section = False
    section_lines = []
    for line in lines:
        if f"=== {section_name} ===" in line:
            in_section = True
            continue
        if in_section:
            if line.startswith("=== ") and "===" in line[4:]:
                break
            section_lines.append(line)
    return "\n".join(section_lines).strip()


def _read_source():
    solution_file = os.path.join(SOLUTION_DIR, "Solution.java")
    if not os.path.exists(solution_file):
        pytest.skip("Solution.java not found")
    with open(solution_file, "r") as f:
        return f.read()


